{
  "function_path": "pandas/core/reshape/pivot.py",
  "function_name": "__internal_pivot_table",
  "justification": "This function is the internal workhorse called by the public pivot_table function for any non-list aggfunc. It: (1) validates value labels exist in data and filters the DataFrame to relevant columns; (2) groups data by concatenation of index+column keys and applies the aggregation function; (3) drops all-NaN rows if dropna is set; (4) if the result has a MultiIndex, unstacks the column-key levels to create a 2D pivot layout using fill_value for missing combinations; (5) if dropna is false, reindexes both axes against the full Cartesian product of level values; (6) sorts columns if requested, fills remaining NaN values, handles integer downcasting for len aggregations; (7) if margins are requested, calls _add_margins to append row/column totals; (8) drops redundant top-level column headers and transposes if no row index was specified."
}

